import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

// AdminDashboard — protected page where ADMIN can create new events
function AdminDashboard() {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user') || 'null');

  // Form fields for creating a new event
  const [name,         setName]         = useState('');
  const [department,   setDepartment]   = useState('');
  const [eventDate,    setEventDate]    = useState('');
  const [eventTime,    setEventTime]    = useState('');
  const [venue,        setVenue]        = useState('');
  const [ticketPrice,  setTicketPrice]  = useState('');
  const [totalTickets, setTotalTickets] = useState('');

  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState('');
  const [success, setSuccess] = useState('');

  function handleLogout() {
    localStorage.removeItem('user');
    navigate('/login');
  }

  function resetForm() {
    setName(''); setDepartment(''); setEventDate('');
    setEventTime(''); setVenue(''); setTicketPrice(''); setTotalTickets('');
  }

  async function handleCreateEvent(e) {
    e.preventDefault();
    setError(''); setSuccess('');

    // Basic client-side validation
    if (!name.trim() || !department.trim() || !eventDate || !eventTime || !venue.trim()) {
      setError('Please fill in all required fields.');
      return;
    }
    if (parseInt(ticketPrice) < 0 || isNaN(parseInt(ticketPrice))) {
      setError('Ticket price must be 0 or greater.');
      return;
    }
    if (parseInt(totalTickets) <= 0 || isNaN(parseInt(totalTickets))) {
      setError('Total tickets must be at least 1.');
      return;
    }

    setLoading(true);
    try {
      const response = await fetch('http://localhost:8081/events', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name:         name.trim(),
          department:   department.trim(),
          eventDate,
          eventTime,
          venue:        venue.trim(),
          ticketPrice:  parseInt(ticketPrice),
          totalTickets: parseInt(totalTickets)
        })
      });
      const data = await response.json();

      if (response.ok && data.success) {
        setSuccess(`✅ Event "${name}" created successfully! (ID: ${data.eventId})`);
        resetForm();
      } else {
        setError(data.message || 'Failed to create event. Please try again.');
      }
    } catch (err) {
      setError('Cannot connect to server. Make sure the backend is running on port 8081.');
    }
    setLoading(false);
  }

  return (
    <div className="page-wrapper">
      {/* Navbar */}
      <nav className="navbar">
        <div className="nav-brand">🎟️ Tech Fest 2026</div>
        <div className="nav-actions">
          <span className="nav-user admin-badge">👑 {user?.username} (Admin)</span>
          <button className="btn-nav" onClick={() => navigate('/events')}>View Events</button>
          <button className="btn-nav btn-danger-nav" onClick={handleLogout}>Logout</button>
        </div>
      </nav>

      <div className="page-content">
        <div className="page-header">
          <h1>⚙️ Admin Dashboard</h1>
          <p>Create and manage events for Tech Fest 2026</p>
        </div>

        <div className="admin-card">
          <h2>Create New Event</h2>

          {error   && <div className="error-banner">{error}</div>}
          {success && <div className="success-banner">{success}</div>}

          <form onSubmit={handleCreateEvent} noValidate>
            {/* Event Name */}
            <div className="form-group">
              <label htmlFor="admin-event-name">Event Name *</label>
              <input
                id="admin-event-name"
                type="text"
                placeholder="e.g. Hackathon 2026"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>

            {/* Department */}
            <div className="form-group">
              <label htmlFor="admin-dept">Department *</label>
              <input
                id="admin-dept"
                type="text"
                placeholder="e.g. Computer Science"
                value={department}
                onChange={(e) => setDepartment(e.target.value)}
              />
            </div>

            {/* Date and Time in a row */}
            <div className="card-row">
              <div className="form-group">
                <label htmlFor="admin-date">Event Date *</label>
                <input
                  id="admin-date"
                  type="date"
                  value={eventDate}
                  onChange={(e) => setEventDate(e.target.value)}
                />
              </div>
              <div className="form-group">
                <label htmlFor="admin-time">Event Time *</label>
                <input
                  id="admin-time"
                  type="time"
                  value={eventTime}
                  onChange={(e) => setEventTime(e.target.value)}
                />
              </div>
            </div>

            {/* Venue */}
            <div className="form-group">
              <label htmlFor="admin-venue">Venue *</label>
              <input
                id="admin-venue"
                type="text"
                placeholder="e.g. College Auditorium"
                value={venue}
                onChange={(e) => setVenue(e.target.value)}
              />
            </div>

            {/* Price and Tickets in a row */}
            <div className="card-row">
              <div className="form-group">
                <label htmlFor="admin-price">Ticket Price (₹) *</label>
                <input
                  id="admin-price"
                  type="number"
                  placeholder="e.g. 100"
                  min="0"
                  value={ticketPrice}
                  onChange={(e) => setTicketPrice(e.target.value)}
                />
              </div>
              <div className="form-group">
                <label htmlFor="admin-tickets">Total Tickets *</label>
                <input
                  id="admin-tickets"
                  type="number"
                  placeholder="e.g. 50"
                  min="1"
                  value={totalTickets}
                  onChange={(e) => setTotalTickets(e.target.value)}
                />
              </div>
            </div>

            <div className="button-row">
              <button id="create-event-btn" type="submit" className="btn-primary" disabled={loading}>
                {loading ? 'Creating Event...' : '+ Create Event'}
              </button>
              <button type="button" className="btn-secondary" onClick={resetForm}>
                Reset
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
